import { ChatFlowCallbackHandler } from 'flowise';

const biasHandler: ChatFlowCallbackHandler = {
  handleLLMEnd(output) {
    const text = output.generations[0][0].text;
    const biasScore = detectBias(text);
    if (biasScore > 0.7) {
      console.warn('BIAS DETECTED:', { score: biasScore, text });
      output.generations[0][0].text += '\n[⚠️ BIAS WARNING: High bias score detected]';
    }
  }
};

function detectBias(text: string): number {
  const biasKeywords = {
    gendered: /he|she|his|her|man|woman|mr|ms|nurse|engineer/i,
    racial: /black|white|asian|ethnic/i
  };
  return Object.values(biasKeywords).reduce((score, pattern) => {
    if (pattern.test(text)) score += 0.3;
    return score;
  }, 0);
}

import { VectorStoreRetrieverCallbackHandler } from 'flowise';

const vectorBiasHandler: VectorStoreRetrieverCallbackHandler = {
  handleRetrievalEnd(documents) {
    const biasMetrics = documents.map(doc => ({
      doc_id: doc.metadata.id,
      demographic_mentions: extractDemographics(doc.pageContent),
      relevance_score: doc.metadata.score || 0
    }));

    const highBiasRetrievals = biasMetrics.filter(
      m => m.demographic_mentions.length > 0 && m.relevance_score < 0.8
    );

    if (highBiasRetrievals.length > 0) {
      console.error('VECTOR BIAS DETECTED:', highBiasRetrievals);
    }
  }
};

function extractDemographics(text: string): string[] {
  const patterns = [
    /black|white|african|asian|latino/i,
    /male|female|man|woman|gender/i,
    /age\s*\d+|young|old|senior/i
  ];
  return patterns.filter(p => p.test(text)).map(p => p.source);
}

const agentHandoffTracer = {
  trackContext(flowState: any, agentId: string) {
    const biasContext = flowState.session.bias_flags || [];
    const currentBiasScore = calculateBiasScore(flowState.output);

    if (biasContext.length > 0 && currentBiasScore > 0.5) {
      console.error(`AGENT ${agentId} LOST BIAS CONTEXT:`, {
        previous_flags: biasContext,
        current_bias: currentBiasScore,
        handoff_drop: true
      });
    }

    // Persist bias context for next agent
    flowState.session.bias_flags = [
      ...biasContext,
      { agent: agentId, score: currentBiasScore, timestamp: Date.now() }
    ];
  }
};

function calculateBiasScore(output: string): number {
  // Simplified bias scoring
  const toxicSpanScore = output.match(/\b(he|she|his|her)\b/gi)?.length || 0;
  return Math.min(toxicSpanScore / 10, 1.0);
}

