import { BaseChatNode } from 'flowise';

export class BiasGuardrailNode extends BaseChatNode {
  async execute() {
    const inputText = this.input;
    const biasAnalysis = await this.analyzeBias(inputText);

    if (biasAnalysis.score > 0.7) {
      return {
        text: this.generateNeutralResponse(inputText, biasAnalysis),
        metadata: { bias_mitigated: true, original_score: biasAnalysis.score }
      };
    }

    return { text: inputText };
  }

  private async analyzeBias(text: string) {
    // Mock bias analysis
    return {
      score: Math.random(),
      issues: ['gendered_language', 'stereotypes']
    };
  }

  private generateNeutralResponse(original: string, analysis: any) {
    return `Neutralized response: ${original.replace(/he|she/gi, 'they')}\n[Mitigated: ${analysis.issues.join(', ')}]`;
  }
}

// Add to VectorStore node configuration
const diverseRetrievalConfig = {
  filter: {
    demographic_balance: true,
    max_bias_score: 0.3,
    diversity_check: (docs: any[]) => {
      const demographics = docs.flatMap(doc => 
        extractDemographics(doc.pageContent)
      );
      const uniqueDemos = new Set(demographics);
      return uniqueDemos.size > 2 ? docs : docs.slice(0, 1);
    }
  },
  rerank: true
};

function extractDemographics(text: string): string[] {
  return text.match(/black|white|asian|latino|male|female/gi) || [];
}

// Usage in Flowise VectorStore node
vectorStoreNode.setConfig({
  ...existingConfig,
  retrievalConfig: diverseRetrievalConfig
});

import { AgentExecutor } from 'flowise';

const biasAwareAgentExecutor = new AgentExecutor({
  agent,
  tools,
  callbacks: [{
    handleAgentAction(action) {
      // Preserve bias context in tool inputs
      action.toolInput = {
        ...action.toolInput,
        bias_context: this.flowState?.session?.bias_flags || [],
        bias_threshold: 0.7
      };
    },
    handleAgentEnd(output) {
      // Update session with new bias metrics
      this.flowState.session.bias_flags.push({
        agent: this.agentId,
        score: calculateBias(output),
        timestamp: Date.now()
      });
    }
  }]
});

function calculateBias(output: string): number {
  const biasIndicators = output.match(/\b(he|she|his|her|man|woman)\b/gi);
  return biasIndicators ? biasIndicators.length * 0.2 : 0;
}

